// ---- Color helpers ----
// These return preview colors for known theme plugins.
// Unknown plugins get a gray fallback.

func adminPreviewColor(pkg string, role string) string {
	switch pkg {
	case "com.flarego.default-theme":
		switch role {
		case "primary":
			return "#2563eb"
		case "secondary":
			return "#3b82f6"
		case "accent":
			return "#60a5fa"
		case "background":
			return "#f9fafb"
		}
	}
	// Fallback for unknown themes
	switch role {
	case "primary":
		return "#6b7280"
	case "secondary":
		return "#9ca3af"
	case "accent":
		return "#d1d5db"
	case "background":
		return "#f3f4f6"
	}
	return "#6b7280"
}

func portalPreviewBg(pkg string) string {
	switch pkg {
	case "com.flarego.default-theme":
		return "linear-gradient(135deg, #667eea 0%, #764ba2 100%)"
	}
	return "linear-gradient(135deg, #6b7280 0%, #9ca3af 100%)"
}

func portalPreviewColor(pkg string, role string) string {
	switch pkg {
	case "com.flarego.default-theme":
		switch role {
		case "primary":
			return "#ffffff"
		case "button":
			return "#4f46e5"
		case "text":
			return "#ffffff"
		}
	}
	switch role {
	case "primary":
		return "#ffffff"
	case "button":
		return "#6b7280"
	case "text":
		return "#ffffff"
	}
	return "#6b7280"
}

func portalLogoPosition(pkg string) string {
	switch pkg {
	case "com.flarego.default-theme":
		return "top"
	}
	return "top"
}

func portalLogoPositionLabel(pkg string) string {
	pos := portalLogoPosition(pkg)
	if pos == "center" {
		return "Center"
	}
	return "Top"
}

